+    #[test]
+    fn btrfs_write_rename_directory_over_nonempty_directory_returns_enotempty() {
+        let (fs, cx) = open_writable_btrfs();
+        let ops: &dyn FsOps = &fs;
+
+        let src = ops
+            .mkdir(
+                &cx,
+                &mut RequestScope::empty(),
+                InodeNumber(1),
+                OsStr::new("src-dir"),
+                0o755,
+                0,
+                0,
+            )
+            .unwrap();
+        let dst = ops
+            .mkdir(
+                &cx,
+                &mut RequestScope::empty(),
+                InodeNumber(1),
+                OsStr::new("dst-dir"),
+                0o755,
+                0,
+                0,
+            )
+            .unwrap();
+        ops.create(
+            &cx,
+            &mut RequestScope::empty(),
+            dst.ino,
+            OsStr::new("child.txt"),
+            0o644,
+            0,
+            0,
+        )
+        .unwrap();
+
+        let err = ops
+            .rename(
+                &cx,
+                &mut RequestScope::empty(),
+                InodeNumber(1),
+                OsStr::new("src-dir"),
+                InodeNumber(1),
+                OsStr::new("dst-dir"),
+            )
+            .unwrap_err();
+        assert_eq!(err.to_errno(), libc::ENOTEMPTY);
+
+        let src_lookup = ops
+            .lookup(
+                &cx,
+                &mut RequestScope::empty(),
+                InodeNumber(1),
+                OsStr::new("src-dir"),
+            )
+            .unwrap();
+        assert_eq!(src_lookup.ino, src.ino);
+        let dst_lookup = ops
+            .lookup(
+                &cx,
+                &mut RequestScope::empty(),
+                InodeNumber(1),
+                OsStr::new("dst-dir"),
+            )
+            .unwrap();
+        assert_eq!(dst_lookup.ino, dst.ino);
+        let child_lookup = ops
+            .lookup(
+                &cx,
+                &mut RequestScope::empty(),
+                dst.ino,
+                OsStr::new("child.txt"),
+            )
+            .unwrap();
+        assert_eq!(child_lookup.kind, FileType::RegularFile);
+    }
